using UnityEngine;
using System;

// --- Delegate definitions ---

public delegate void HealthChangedHandler(int currentHealth, int maxHealth);
public delegate void ScoreChangedHandler(int newScore);
public delegate void EnemyKilledHandler(string enemyName, int experience);
public delegate void GameEventHandler();
public delegate void MessageHandler(string message);
public delegate bool DamageModifierHandler(int damage, ref int modifiedDamage);

// --- Event system using delegates ---

public class GameEvents : MonoBehaviour
{
    // Events
    public static event HealthChangedHandler OnHealthChanged;
    public static event ScoreChangedHandler OnScoreChanged;
    public static event EnemyKilledHandler OnEnemyKilled;
    public static event GameEventHandler OnGameOver;
    public static event GameEventHandler OnGameWin;
    public static event MessageHandler OnMessage;

    // Example: Modify damage
    private static DamageModifierHandler damageModifiers;

    public static void AddDamageModifier(DamageModifierHandler modifier)
    {
        damageModifiers += modifier;
    }

    public static void RemoveDamageModifier(DamageModifierHandler modifier)
    {
        damageModifiers -= modifier;
    }

    // --- Event triggers ---

    public static void TriggerHealthChanged(int current, int max)
    {
        OnHealthChanged?.Invoke(current, max);
    }

    public static void TriggerScoreChanged(int score)
    {
        OnScoreChanged?.Invoke(score);
    }

    public static void TriggerEnemyKilled(string name, int exp)
    {
        OnEnemyKilled?.Invoke(name, exp);
    }

    public static void TriggerGameOver()
    {
        OnGameOver?.Invoke();
    }

    public static void TriggerGameWin()
    {
        OnGameWin?.Invoke();
    }

    public static void TriggerMessage(string message)
    {
        OnMessage?.Invoke(message);
    }

    public static int ModifyDamage(int damage)
    {
        if (damageModifiers != null)
        {
            foreach (DamageModifierHandler modifier in damageModifiers.GetInvocationList())
            {
                int modifiedDamage = damage;
                modifier.Invoke(damage, ref modifiedDamage);
                damage = modifiedDamage;
            }
        }
        return damage;
    }
}

// --- Event listeners ---

public class EventListener : MonoBehaviour
{
    void OnEnable()
    {
        // Subscribe to events
        GameEvents.OnHealthChanged += HandleHealthChanged;
        GameEvents.OnScoreChanged += HandleScoreChanged;
        GameEvents.OnEnemyKilled += HandleEnemyKilled;
        GameEvents.OnGameOver += HandleGameOver;
        GameEvents.OnGameWin += HandleGameWin;
        GameEvents.OnMessage += HandleMessage;

        // Add damage modifier
        GameEvents.AddDamageModifier(HandleDamageModifier);

        Debug.Log("Event listener subscribed!");
    }

    void OnDisable()
    {
        // Unsubscribe to prevent memory leaks
        GameEvents.OnHealthChanged -= HandleHealthChanged;
        GameEvents.OnScoreChanged -= HandleScoreChanged;
        GameEvents.OnEnemyKilled -= HandleEnemyKilled;
        GameEvents.OnGameOver -= HandleGameOver;
        GameEvents.OnGameWin -= HandleGameWin;
        GameEvents.OnMessage -= HandleMessage;

        GameEvents.RemoveDamageModifier(HandleDamageModifier);
    }

    // --- Event handlers ---

    void HandleHealthChanged(int current, int max)
    {
        Debug.Log($"Health: {current}/{max}");
        // Update health bar
    }

    void HandleScoreChanged(int score)
    {
        Debug.Log($"Score: {score}");
        // Update score UI
    }

    void HandleEnemyKilled(string name, int exp)
    {
        Debug.Log($"{name} killed! +{exp} XP");
        // Add experience
    }

    void HandleGameOver()
    {
        Debug.Log("Game Over!");
        // Show game over UI
    }

    void HandleGameWin()
    {
        Debug.Log("You Win!");
        // Show win UI
    }

    void HandleMessage(string message)
    {
        Debug.Log("Message: " + message);
        // Show message
    }

    bool HandleDamageModifier(int damage, ref int modifiedDamage)
    {
        // Example: Reduce damage by 50%
        modifiedDamage = damage / 2;
        Debug.Log($"Damage reduced from {damage} to {modifiedDamage}");
        return true;
    }
}

public class DelegateExample : MonoBehaviour
{
    void Start()
    {
        // Test events
        Debug.Log("=== Testing Events ===");

        GameEvents.TriggerHealthChanged(75, 100);
        GameEvents.TriggerScoreChanged(500);
        GameEvents.TriggerEnemyKilled("Goblin", 20);
        GameEvents.TriggerMessage("Welcome to the dungeon!");

        // Test damage modifiers
        int damage = 100;
        int finalDamage = GameEvents.ModifyDamage(damage);
        Debug.Log($"Final damage: {finalDamage}");
    }
}

